import { useState, useEffect } from "react";

export function Navbar() {
  const [isVisible, setIsVisible] = useState(true);
  const [lastScrollY, setLastScrollY] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;

      // Se rolou para baixo, esconde a navbar
      if (
        currentScrollY > lastScrollY &&
        currentScrollY > 100
      ) {
        setIsVisible(false);
      } else {
        // Se rolou para cima, mostra a navbar
        setIsVisible(true);
      }

      setLastScrollY(currentScrollY);
    };

    window.addEventListener("scroll", handleScroll, {
      passive: true,
    });

    return () =>
      window.removeEventListener("scroll", handleScroll);
  }, [lastScrollY]);

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-transform duration-300 ease-in-out bg-opacity-80 ${
        isVisible ? "translate-y-0" : "-translate-y-full"
      }`}
    >
      <div className="bg-slate-950/80 backdrop-blur-md border-b border-slate-800/50">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16 sm:h-20">
            {/* Logo */}
            <svg
              width="80"
              height="80"
              viewBox="0 0 500 500"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              xmlnsXlink="http://www.w3.org/1999/xlink"
              className=""
            >
              <rect
                width="500"
                height="500"
                fill="url(#pattern0_1_2)"
              />
              <defs>
                <pattern
                  id="pattern0_1_2"
                  patternContentUnits="objectBoundingBox"
                  width="1"
                  height="1"
                >
                  <use
                    xlinkHref="#image0_1_2"
                    transform="scale(0.002)"
                  />
                </pattern>
                <image
                  id="image0_1_2"
                  width="500"
                  height="500"
                  preserveAspectRatio="none"
                  xlinkHref="data:image/png;base64,"
                />
              </defs>
            </svg>

            {/* Botão Entrar */}
            <button className="cursor-pointer px-4 sm:px-6 py-2 sm:py-2.5 bg-gradient-to-r from-purple-600 to-purple-500 text-white rounded-lg font-semibold text-sm sm:text-base shadow-lg shadow-purple-500/30 hover:shadow-xl hover:shadow-purple-500/40 hover:-translate-y-0.5 transition-all duration-200">
              Entrar
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
}